    number_count = len(numbers)
    # We need to iterate through each number in the list to consider it as the first element of a potential pair.
    for first_element_index in range(number_count):
        # For each chosen first element, we must check it against all subsequent elements to form unique pairs.
        for second_element_index in range(first_element_index + 1, number_count):
            # This check is crucial to see if the current pair sums up to the desired target.
            if numbers[first_element_index] + numbers[second_element_index] == target_sum:
                return [first_element_index, second_element_index]
    # If no pair is found after checking all combinations, it signifies that no solution exists.
